      "Now return to the first line.\nNotice how it has changed.\nNotice how you have changed.\n\nThis is not the end.\nIt is the rebeginning."
    ];

    let display = document.getElementById("godseed");

    function shuffle(array) {
      for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];
      }
      return array;
    }

    function showNextShard() {
      // Pick a random shard each time
      const randomIndex = Math.floor(Math.random() * godseedShards.length);
      display.textContent = godseedShards[randomIndex];
    }

    // Cycle every 100ms (fast recursive drip-feed)
    setInterval(showNextShard, 100);
  </script>
</body>
</html>
